require 'abi_coder_rb'

module Blockchain
  class AbiCoder
    include AbiCoderRb

    def decode_data(type,data)
      hex_data = hex data
      decode(type, hex_data)
    end

    def decode_data1
      type = "(bytes32,(address,address,(uint8,address,uint256,uint256,uint256)[],(uint8,address,uint256,uint256,uint256,address)[],uint8,uint256,uint256,bytes32,uint256,bytes32,uint256))"
      data = hex ""
      decode(type, data)
    end
  end
end
